import { useState, useEffect, useCallback, useMemo } from "react";
import { useTranslation } from "react-i18next";
import { useToast } from "@/hooks/use-toast";
import { supabase } from "@/integrations/supabase/client";
import { useRestaurantsPaginated } from "@/hooks/useRestaurantsPaginated";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Progress } from "@/components/ui/progress";
import {
  Globe, Loader2, ExternalLink, Copy, Check, Plus, Eye, Share2,
  RefreshCw, ArrowLeft, ChevronRight, Store, FileText, Sparkles, Edit, Search,
  X, Clock, Image as ImageIcon, Palette, Link2, Info,
} from "lucide-react";

const AI_SITE_BUILDER_ORIGIN = "https://ai-site-builder-xiaoxiong.lovable.app";
const PROJECTS_API_URL = "https://dxjbiwpsxggaogbpgbde.supabase.co/functions/v1/projects-api";
const GENERATE_API_URL = "https://dxjbiwpsxggaogbpgbde.supabase.co/functions/v1/generate-website";

interface WebProject {
  id: string;
  name?: string;
  business_name?: string;
  slug?: string;
  share_url?: string;
  preview_url?: string;
  edit_url?: string;
  published_url?: string;
  html_content?: string;
  created_at?: string;
  updated_at?: string;
  status?: string;
  published?: boolean;
}

const STEPS = [
  { icon: Store, key: "step1Title" },
  { icon: FileText, key: "step2Title" },
  { icon: Sparkles, key: "step3Title" },
] as const;

const AdminWebsiteManagement = () => {
  const { t } = useTranslation();
  const { toast } = useToast();
  const { localizeRestaurant } = useLocalizedContent();

  const [projects, setProjects] = useState<WebProject[]>([]);
  const [loadingProjects, setLoadingProjects] = useState(true);

  // Inline step flow
  const [showAddForm, setShowAddForm] = useState(false);
  const [step, setStep] = useState(1);
  const [selectedId, setSelectedId] = useState<string>("");
  const [selectedRestaurant, setSelectedRestaurant] = useState<any>(null);
  const [form, setForm] = useState({
    business_name: "", business_type: "", address: "", phone: "", email: "",
    description: "", logo_url: "", cover_image_url: "",
    style_reference_url: "",
    operating_hours: "", price_range: "", slogan: "", style_preference: "", color_scheme: "",
    reservation_url: "", site_goal: "", target_audience: "", page_structure: "single",
  });
  const [contentRefUrls, setContentRefUrls] = useState<string[]>([""]);
  const [hoursMode, setHoursMode] = useState<"visual" | "json">("visual");
  // Hours rows: { label, value }. Label drives JSON key, fully customizable.
  const [hoursRows, setHoursRows] = useState<Array<{ label: string; value: string }>>([]);
  const [generating, setGenerating] = useState(false);
  const [result, setResult] = useState<any>(null);
  const [copied, setCopied] = useState(false);

  // Debounced search for restaurant selection (server-side)
  const [searchTerm, setSearchTerm] = useState("");
  const [debouncedSearch, setDebouncedSearch] = useState("");

  useEffect(() => {
    const timer = setTimeout(() => setDebouncedSearch(searchTerm), 400);
    return () => clearTimeout(timer);
  }, [searchTerm]);

  const { data: searchResults, isLoading: searchLoading } = useRestaurantsPaginated(
    { search: debouncedSearch || undefined },
    0,
    40,
  );

  const restaurants = useMemo(() => searchResults?.data || [], [searchResults]);

  const getToken = useCallback(async () => {
    const { data } = await supabase.auth.getSession();
    return data?.session?.access_token || null;
  }, []);

  const fetchProjects = useCallback(async () => {
    setLoadingProjects(true);
    try {
      const token = await getToken();
      if (!token) return;
      const res = await fetch(`${PROJECTS_API_URL}?action=user_projects`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      if (res.ok) {
        const json = await res.json();
        const rawList = Array.isArray(json) ? json : json?.data || json?.projects || [];
        const mapped = rawList.map((p: any) => {
          const projectId = p.id;
          return {
            ...p,
            business_name: p.business_name || p.name || "",
            preview_url: p.published_url || p.preview_url || "",
            edit_url: p.edit_url || (projectId ? `${AI_SITE_BUILDER_ORIGIN}/workspace/${projectId}` : ""),
            share_url: p.published_url || p.share_url || "",
          };
        });
        setProjects(mapped);
      }
    } catch (e) {
      console.error("Failed to fetch projects:", e);
    } finally {
      setLoadingProjects(false);
    }
  }, [getToken]);

  useEffect(() => { fetchProjects(); }, [fetchProjects]);

  const DEFAULT_DAY_LABELS = useMemo(() => {
    const map: Record<string, string> = {
      monday: t("merchant.websiteManagement.days.monday", "周一"),
      tuesday: t("merchant.websiteManagement.days.tuesday", "周二"),
      wednesday: t("merchant.websiteManagement.days.wednesday", "周三"),
      thursday: t("merchant.websiteManagement.days.thursday", "周四"),
      friday: t("merchant.websiteManagement.days.friday", "周五"),
      saturday: t("merchant.websiteManagement.days.saturday", "周六"),
      sunday: t("merchant.websiteManagement.days.sunday", "周日"),
    };
    return map;
  }, [t]);

  const DEFAULT_DAY_KEYS = ["monday", "tuesday", "wednesday", "thursday", "friday", "saturday", "sunday"];

  const formatDayHours = useCallback((entry: any): string => {
    if (!entry) return "";
    if (typeof entry === "string") return entry;
    if (Array.isArray(entry)) {
      return entry
        .map((s: any) => (s?.open && s?.close ? `${s.open}-${s.close}` : ""))
        .filter(Boolean)
        .join(", ");
    }
    if (typeof entry === "object") {
      const parts: string[] = [];
      if (entry.open && entry.close) parts.push(`${entry.open}-${entry.close}`);
      if (entry.open2 && entry.close2) parts.push(`${entry.open2}-${entry.close2}`);
      return parts.join(", ");
    }
    return "";
  }, []);

  const parseHoursToRows = useCallback((raw: any): Array<{ label: string; value: string }> => {
    let obj: any = raw;
    if (typeof raw === "string") {
      try { obj = JSON.parse(raw); } catch { obj = null; }
    }
    if (!obj || typeof obj !== "object") {
      return DEFAULT_DAY_KEYS.map((k) => ({ label: DEFAULT_DAY_LABELS[k], value: "" }));
    }
    const rows: Array<{ label: string; value: string }> = [];
    // Standard days first, in order
    DEFAULT_DAY_KEYS.forEach((k) => {
      rows.push({ label: DEFAULT_DAY_LABELS[k], value: formatDayHours(obj[k]) });
    });
    // Then any extra (custom) keys
    Object.keys(obj).forEach((k) => {
      if (!DEFAULT_DAY_KEYS.includes(k)) {
        rows.push({ label: k, value: formatDayHours(obj[k]) });
      }
    });
    return rows;
  }, [formatDayHours, DEFAULT_DAY_LABELS]);

  const labelToKey = useCallback((label: string): string => {
    const trimmed = label.trim();
    // map localized day labels back to canonical English keys
    const reverse = Object.entries(DEFAULT_DAY_LABELS).find(([, v]) => v === trimmed);
    return reverse ? reverse[0] : trimmed;
  }, [DEFAULT_DAY_LABELS]);

  const serializeHoursFromRows = useCallback((rows: Array<{ label: string; value: string }>): string => {
    const out: Record<string, any> = {};
    rows.forEach(({ label, value }) => {
      const v = (value || "").trim();
      const k = labelToKey(label);
      if (!k || !v) return;
      const segments = v.split(/[,，]/).map((s) => s.trim()).filter(Boolean);
      const slots: { open: string; close: string }[] = [];
      segments.forEach((seg) => {
        const m = seg.match(/^(\d{1,2}:\d{2})\s*[-–~至]\s*(\d{1,2}:\d{2})$/);
        if (m) slots.push({ open: m[1], close: m[2] });
      });
      if (slots.length === 1) {
        out[k] = slots[0];
      } else if (slots.length >= 2) {
        out[k] = { open: slots[0].open, close: slots[0].close, open2: slots[1].open, close2: slots[1].close };
      } else {
        out[k] = v;
      }
    });
    return Object.keys(out).length ? JSON.stringify(out) : "";
  }, [labelToKey]);

  // Auto-fill form when restaurant selected
  useEffect(() => {
    if (!selectedRestaurant) return;
    const r = selectedRestaurant;
    const hoursStr = typeof r.opening_hours === "string"
      ? r.opening_hours
      : r.opening_hours ? JSON.stringify(r.opening_hours) : "";
    setForm({
      business_name: r.name || "",
      business_type: r.type?.[0] || "",
      address: r.address || "",
      phone: r.phone || "",
      email: r.email || "",
      description: r.description || "",
      logo_url: r.image_url || "",
      cover_image_url: r.image_url || "",
      style_reference_url: "",
      operating_hours: hoursStr,
      price_range: r.price_range || "",
      slogan: "", style_preference: "", color_scheme: "",
      reservation_url: r.booking_url || r.takeaway_url || "",
      site_goal: "", target_audience: "", page_structure: "single",
    });
    setHoursRows(parseHoursToRows(r.opening_hours));
    setHoursMode("visual");
    const origin = typeof window !== "undefined" ? window.location.origin : "https://xx-market.lovable.app";
    setContentRefUrls([`${origin}/restaurant/${r.id}`]);
  }, [selectedRestaurant, parseHoursToRows]);

  const updateField = (key: string, value: string) => {
    setForm((prev) => ({ ...prev, [key]: value }));
  };

  const handleSelectRestaurant = (r: any) => {
    setSelectedId(r.id);
    setSelectedRestaurant(r);
    setStep(2);
  };

  const handleBackToList = () => {
    setShowAddForm(false);
    setStep(1);
    setSelectedId("");
    setSelectedRestaurant(null);
    setResult(null);
    setSearchTerm("");
  };

  const handleGenerate = async () => {
    if (!selectedId) {
      toast({ title: t("merchant.websiteManagement.selectRestaurant"), variant: "destructive" });
      return;
    }
    setGenerating(true);
    setStep(3);
    try {
      const token = await getToken();
      if (!token) {
        toast({ title: t("merchant.generateWebsite.error401"), variant: "destructive" });
        setStep(2);
        return;
      }

      const body: Record<string, any> = {
        access_token: token,
        business_name: form.business_name,
        business_type: form.business_type,
        address: form.address,
        phone: form.phone,
        description: form.description,
        logo_url: form.logo_url,
        cover_image_url: form.cover_image_url,
      };
      if (form.style_reference_url) body.style_reference_url = form.style_reference_url;
      const cleanContentRefs = contentRefUrls.map((u) => u.trim()).filter(Boolean).slice(0, 3);
      if (cleanContentRefs.length > 0) {
        body.content_reference_url = cleanContentRefs[0];
        if (cleanContentRefs.length > 1) body.content_reference_urls = cleanContentRefs;
      }
      if (form.email) body.email = form.email;
      const hoursOut = hoursMode === "visual" ? serializeHoursFromRows(hoursRows) : form.operating_hours;
      if (hoursOut) body.operating_hours = hoursOut;
      if (form.price_range) body.price_range = form.price_range;
      if (form.slogan) body.slogan = form.slogan;
      if (form.style_preference) body.style_preference = form.style_preference;
      if (form.color_scheme) body.color_scheme = form.color_scheme;
      if (form.reservation_url) body.reservation_url = form.reservation_url;
      if (form.site_goal) body.site_goal = form.site_goal;
      if (form.target_audience) body.target_audience = form.target_audience;
      if (form.page_structure) body.page_structure = form.page_structure;

      if (selectedRestaurant) {
        if (selectedRestaurant.social_media) body.social_links = selectedRestaurant.social_media;
        if (selectedRestaurant.menu_images?.length) body.gallery_images = selectedRestaurant.menu_images;
      }

      const res = await fetch(GENERATE_API_URL, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(body),
      });

      if (!res.ok) {
        const status = res.status;
        const key = status === 401 ? "error401" : status === 403 ? "error403" : status === 429 ? "error429" : "errorGeneric";
        toast({ title: t(`merchant.generateWebsite.${key}`), variant: "destructive" });
        setStep(2);
        return;
      }

      const data = await res.json();
      if (data.success) {
        setResult(data);
        toast({ title: t("merchant.generateWebsite.success") });
        fetchProjects();
      } else {
        toast({ title: t("merchant.generateWebsite.errorGeneric"), variant: "destructive" });
        setStep(2);
      }
    } catch (e: any) {
      toast({ title: t("merchant.generateWebsite.errorGeneric"), description: e.message, variant: "destructive" });
      setStep(2);
    } finally {
      setGenerating(false);
    }
  };

  const handleCopy = async (url: string) => {
    await navigator.clipboard.writeText(url);
    setCopied(true);
    toast({ title: t("merchant.generateWebsite.copied") });
    setTimeout(() => setCopied(false), 2000);
  };

  const fields: { key: string; label: string; type?: "textarea" }[] = [
    { key: "business_name", label: t("merchant.websiteManagement.businessName") },
    { key: "business_type", label: t("merchant.websiteManagement.businessType") },
    { key: "address", label: t("merchant.websiteManagement.address") },
    { key: "phone", label: t("merchant.websiteManagement.phone") },
    { key: "email", label: t("merchant.websiteManagement.email") },
    { key: "description", label: t("merchant.websiteManagement.description"), type: "textarea" },
    { key: "logo_url", label: t("merchant.websiteManagement.logoUrl") },
    { key: "cover_image_url", label: t("merchant.websiteManagement.coverImageUrl") },
    { key: "price_range", label: t("merchant.websiteManagement.priceRange") },
    { key: "slogan", label: t("merchant.websiteManagement.slogan") },
    { key: "style_preference", label: t("merchant.websiteManagement.stylePreference") },
    { key: "color_scheme", label: t("merchant.websiteManagement.colorScheme") },
  ];

  const StepIndicator = () => (
    <div className="mb-8">
      <div className="flex items-center justify-between mb-3">
        {STEPS.map((s, i) => {
          const StepIcon = s.icon;
          const stepNum = i + 1;
          const isActive = step === stepNum;
          const isDone = step > stepNum;
          return (
            <div key={i} className="flex items-center flex-1">
              <div className="flex items-center gap-2">
                <div className={`w-9 h-9 rounded-full flex items-center justify-center text-sm font-semibold transition-all ${
                  isActive ? "bg-primary text-primary-foreground shadow-md" :
                  isDone ? "bg-primary/20 text-primary" :
                  "bg-muted text-muted-foreground"
                }`}>
                  {isDone ? <Check className="h-4 w-4" /> : <StepIcon className="h-4 w-4" />}
                </div>
                <span className={`text-sm font-medium hidden sm:inline ${
                  isActive ? "text-foreground" : "text-muted-foreground"
                }`}>
                  {t(`merchant.websiteManagement.${s.key}`)}
                </span>
              </div>
              {i < STEPS.length - 1 && (
                <div className="flex-1 mx-3">
                  <div className={`h-0.5 rounded-full transition-all ${
                    step > stepNum ? "bg-primary" : "bg-border"
                  }`} />
                </div>
              )}
            </div>
          );
        })}
      </div>
      <Progress value={(step / 3) * 100} className="h-1.5" />
    </div>
  );

  return (
    <div>
      {/* Header */}
      <div className="mb-6 flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold">{t("merchant.websiteManagement", "网站管理")}</h1>
          <p className="text-muted-foreground mt-1">{t("merchant.websiteManagement.subtitle")}</p>
        </div>
        <div className="flex gap-2">
          {!showAddForm && (
            <>
              <Button variant="outline" size="icon" onClick={fetchProjects} disabled={loadingProjects}>
                <RefreshCw className={`h-4 w-4 ${loadingProjects ? "animate-spin" : ""}`} />
              </Button>
              <Button onClick={() => { setShowAddForm(true); setStep(1); setSelectedId(""); setResult(null); setSearchTerm(""); }}>
                <Plus className="h-4 w-4 mr-2" />
                {t("merchant.websiteManagement.addNew")}
              </Button>
            </>
          )}
          {showAddForm && (
            <Button variant="outline" onClick={handleBackToList}>
              <ArrowLeft className="h-4 w-4 mr-2" />
              {t("merchant.websiteManagement.backToList")}
            </Button>
          )}
        </div>
      </div>

      {/* === PROJECT LIST === */}
      {!showAddForm && (
        <>
          {loadingProjects ? (
            <div className="flex items-center justify-center py-12">
              <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
            </div>
          ) : projects.length === 0 ? (
            <Card>
              <CardContent className="flex flex-col items-center justify-center py-12 text-center">
                <Globe className="h-12 w-12 text-muted-foreground/50 mb-4" />
                <p className="text-muted-foreground mb-4">{t("merchant.websiteManagement.noProjects")}</p>
                <Button onClick={() => { setShowAddForm(true); setStep(1); }}>
                  <Plus className="h-4 w-4 mr-2" />
                  {t("merchant.websiteManagement.addNew")}
                </Button>
              </CardContent>
            </Card>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {projects.map((project) => {
                const hasHtmlContent = Boolean(project.html_content?.trim());
                return (
                  <Card
                    key={project.id}
                    className="overflow-hidden cursor-pointer hover:shadow-lg transition-shadow group"
                    onClick={async () => {
                      if (project.edit_url) {
                        const token = await getToken();
                        const url = token ? `${project.edit_url}?token=${token}` : project.edit_url;
                        window.open(url, "_blank", "noopener,noreferrer");
                      }
                    }}
                  >
                    <div className="aspect-video bg-muted overflow-hidden relative">
                      {hasHtmlContent ? (
                        <iframe
                          srcDoc={project.html_content!}
                          className="w-[400%] h-[400%] origin-top-left scale-[0.25] pointer-events-none border-0"
                          sandbox="allow-scripts"
                          title={project.business_name || project.name || ""}
                        />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center">
                          <Globe className="h-10 w-10 text-muted-foreground/30" />
                        </div>
                      )}
                      <div className="absolute inset-0 bg-black/0 group-hover:bg-black/40 transition-all duration-200 flex items-center justify-center">
                        <div className="opacity-0 group-hover:opacity-100 transition-opacity duration-200 bg-white rounded-full p-3 shadow-lg">
                          <Edit className="h-6 w-6 text-primary" />
                        </div>
                      </div>
                    </div>
                    <CardContent className="p-4">
                      <h3 className="font-semibold truncate mb-1">{project.business_name || project.name || project.id}</h3>
                      {project.created_at && (
                        <p className="text-xs text-muted-foreground mb-3">
                          {new Date(project.created_at).toLocaleDateString()}
                        </p>
                      )}
                      <div className="flex gap-2 flex-wrap" onClick={(e) => e.stopPropagation()}>
                        {project.preview_url && (
                          <Button variant="outline" size="sm" asChild>
                            <a href={project.preview_url} target="_blank" rel="noopener noreferrer">
                              <Eye className="h-3 w-3 mr-1" />
                              {t("merchant.generateWebsite.preview")}
                            </a>
                          </Button>
                        )}
                        {project.share_url && (
                          <Button variant="outline" size="sm" onClick={() => handleCopy(project.share_url!)}>
                            {copied ? <Check className="h-3 w-3 mr-1" /> : <Share2 className="h-3 w-3 mr-1" />}
                            {t("merchant.generateWebsite.share")}
                          </Button>
                        )}
                      </div>
                    </CardContent>
                  </Card>
                );
              })}
            </div>
          )}
        </>
      )}

      {/* === INLINE STEP FLOW === */}
      {showAddForm && (
        <Card className="border-0 shadow-none">
          <CardContent className="p-0 sm:p-6">
            <StepIndicator />

            {/* Step 1: Search & Select Restaurant */}
            {step === 1 && (
              <div className="space-y-4">
                <h3 className="text-lg font-semibold">{t("merchant.websiteManagement.step1Title")}</h3>
                <p className="text-sm text-muted-foreground">{t("admin.websiteManagement.searchHint", "输入建筑名称搜索，从结果中选择")}</p>
                
                {/* Search input */}
                <div className="relative">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                  <Input
                    placeholder={t("admin.websiteManagement.searchPlaceholder", "搜索建筑名称...")}
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-10"
                    autoFocus
                  />
                </div>

                {/* Search results */}
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4 max-h-[60vh] overflow-y-auto">
                  {searchLoading ? (
                    <div className="col-span-full flex justify-center py-8">
                      <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
                    </div>
                  ) : !debouncedSearch ? (
                    <div className="col-span-full text-center py-8 text-muted-foreground">
                      <Search className="h-8 w-8 mx-auto mb-2 opacity-40" />
                      <p>{t("admin.websiteManagement.typeToSearch", "请输入关键词开始搜索")}</p>
                    </div>
                  ) : restaurants.length === 0 ? (
                    <div className="col-span-full text-center py-8 text-muted-foreground">
                      {t("common.noResults", "没有找到结果")}
                    </div>
                  ) : restaurants.map((r: any) => {
                    const localized = localizeRestaurant(r);
                    return (
                      <Card
                        key={r.id}
                        className="cursor-pointer hover:border-primary hover:shadow-md transition-all"
                        onClick={() => handleSelectRestaurant(r)}
                      >
                        <CardContent className="p-4 flex items-center gap-3">
                          {r.image_url ? (
                            <img src={r.image_url} alt={localized.name} className="w-12 h-12 rounded-lg object-cover" />
                          ) : (
                            <div className="w-12 h-12 rounded-lg bg-muted flex items-center justify-center">
                              <Store className="h-5 w-5 text-muted-foreground" />
                            </div>
                          )}
                          <div className="flex-1 min-w-0">
                            <p className="font-medium truncate">{localized.name}</p>
                            <p className="text-xs text-muted-foreground truncate">{r.address}</p>
                          </div>
                          <ChevronRight className="h-4 w-4 text-muted-foreground shrink-0" />
                        </CardContent>
                      </Card>
                    );
                  })}
                </div>
              </div>
            )}

            {/* Step 2: Fill Info */}
            {step === 2 && (
              <div className="space-y-6">
                {/* Sticky header with selected restaurant context */}
                <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3 pb-4 border-b">
                  <div className="flex items-center gap-3 min-w-0">
                    {selectedRestaurant?.image_url ? (
                      <img src={selectedRestaurant.image_url} alt="" className="w-10 h-10 rounded-lg object-cover shrink-0" />
                    ) : (
                      <div className="w-10 h-10 rounded-lg bg-muted flex items-center justify-center shrink-0">
                        <Store className="h-5 w-5 text-muted-foreground" />
                      </div>
                    )}
                    <div className="min-w-0">
                      <h3 className="text-lg font-semibold truncate">{form.business_name || t("merchant.websiteManagement.step2Title")}</h3>
                      <p className="text-xs text-muted-foreground truncate">{form.address}</p>
                    </div>
                  </div>
                  <Button variant="ghost" size="sm" onClick={() => setStep(1)} className="self-start sm:self-auto">
                    <ArrowLeft className="h-4 w-4 mr-1" />
                    {t("merchant.websiteManagement.prevStep")}
                  </Button>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                  {/* LEFT COLUMN */}
                  <div className="space-y-6">
                    {/* Basic Info Card */}
                    <Card className="border-border/60">
                      <CardContent className="p-5 space-y-4">
                        <div className="flex items-center gap-2">
                          <div className="h-8 w-8 rounded-lg bg-primary/10 flex items-center justify-center">
                            <Store className="h-4 w-4 text-primary" />
                          </div>
                          <h4 className="text-sm font-semibold">{t("merchant.websiteManagement.basicInfo")}</h4>
                        </div>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                          {fields.filter(f => ["business_name", "business_type", "phone", "email"].includes(f.key)).map(({ key, label }) => (
                            <div key={key} className="space-y-1.5">
                              <Label htmlFor={key} className="text-xs text-muted-foreground">{label}</Label>
                              <Input id={key} value={(form as any)[key]} onChange={(e) => updateField(key, e.target.value)} />
                            </div>
                          ))}
                        </div>
                        <div className="space-y-1.5">
                          <Label htmlFor="address" className="text-xs text-muted-foreground">{t("merchant.websiteManagement.address")}</Label>
                          <Input id="address" value={form.address} onChange={(e) => updateField("address", e.target.value)} />
                        </div>
                        <div className="space-y-1.5">
                          <Label htmlFor="description" className="text-xs text-muted-foreground">{t("merchant.websiteManagement.description")}</Label>
                          <Textarea id="description" value={form.description} onChange={(e) => updateField("description", e.target.value)} rows={3} />
                        </div>
                      </CardContent>
                    </Card>

                    {/* Media Card */}
                    <Card className="border-border/60">
                      <CardContent className="p-5 space-y-4">
                        <div className="flex items-center gap-2">
                          <div className="h-8 w-8 rounded-lg bg-primary/10 flex items-center justify-center">
                            <ImageIcon className="h-4 w-4 text-primary" />
                          </div>
                          <h4 className="text-sm font-semibold">{t("merchant.websiteManagement.mediaSection")}</h4>
                        </div>
                        <div className="space-y-3">
                          {fields.filter(f => ["logo_url", "cover_image_url"].includes(f.key)).map(({ key, label }) => (
                            <div key={key} className="space-y-1.5">
                              <Label htmlFor={key} className="text-xs text-muted-foreground">{label}</Label>
                              <Input id={key} value={(form as any)[key]} onChange={(e) => updateField(key, e.target.value)} />
                            </div>
                          ))}
                        </div>
                      </CardContent>
                    </Card>

                    {/* Operating Hours Card */}
                    <Card className="border-border/60">
                      <CardContent className="p-5 space-y-4">
                        <div className="flex items-center justify-between gap-2">
                          <div className="flex items-center gap-2 min-w-0">
                            <div className="h-8 w-8 rounded-lg bg-primary/10 flex items-center justify-center shrink-0">
                              <Clock className="h-4 w-4 text-primary" />
                            </div>
                            <h4 className="text-sm font-semibold truncate">{t("merchant.websiteManagement.operatingHours")}</h4>
                          </div>
                          <Button
                            type="button"
                            variant="ghost"
                            size="sm"
                            className="h-7 text-xs shrink-0"
                            onClick={() => {
                              if (hoursMode === "visual") {
                                const json = serializeHoursFromRows(hoursRows);
                                if (json) updateField("operating_hours", json);
                                setHoursMode("json");
                              } else {
                                setHoursRows(parseHoursToRows(form.operating_hours));
                                setHoursMode("visual");
                              }
                            }}
                          >
                            {hoursMode === "visual"
                              ? t("merchant.websiteManagement.editAsJson", "JSON 编辑")
                              : t("merchant.websiteManagement.editVisual", "可视化编辑")}
                          </Button>
                        </div>
                        {hoursMode === "visual" ? (
                          <>
                            <div className="space-y-2">
                              {hoursRows.map((row, idx) => (
                                <div key={idx} className="flex items-center gap-2">
                                  <Input
                                    className="w-20 shrink-0 text-xs h-9"
                                    value={row.label}
                                    placeholder={t("merchant.websiteManagement.dayLabel", "日子")}
                                    onChange={(e) => {
                                      const next = [...hoursRows];
                                      next[idx] = { ...next[idx], label: e.target.value };
                                      setHoursRows(next);
                                    }}
                                  />
                                  <Input
                                    className="flex-1 h-9"
                                    placeholder={t("merchant.websiteManagement.hoursPlaceholder", "如 12:00-15:00, 19:00-23:00 或 休息")}
                                    value={row.value}
                                    onChange={(e) => {
                                      const next = [...hoursRows];
                                      next[idx] = { ...next[idx], value: e.target.value };
                                      setHoursRows(next);
                                    }}
                                  />
                                  <Button
                                    type="button"
                                    variant="ghost"
                                    size="icon"
                                    className="h-9 w-9 shrink-0 text-muted-foreground hover:text-destructive"
                                    onClick={() => setHoursRows((arr) => arr.filter((_, i) => i !== idx))}
                                  >
                                    <X className="h-4 w-4" />
                                  </Button>
                                </div>
                              ))}
                            </div>
                            <Button
                              type="button"
                              variant="outline"
                              size="sm"
                              className="w-full"
                              onClick={() => setHoursRows((arr) => [...arr, { label: "", value: "" }])}
                            >
                              <Plus className="h-3.5 w-3.5 mr-1" />
                              {t("merchant.websiteManagement.addCustomDay", "添加自定义日子（如：红日、节假日）")}
                            </Button>
                          </>
                        ) : (
                          <Textarea
                            value={form.operating_hours}
                            onChange={(e) => updateField("operating_hours", e.target.value)}
                            rows={6}
                            className="font-mono text-xs"
                            placeholder='{"monday":{"open":"12:00","close":"22:00"}, "红日":"休息"}'
                          />
                        )}
                      </CardContent>
                    </Card>
                  </div>

                  {/* RIGHT COLUMN */}
                  <div className="space-y-6">
                    {/* Content Reference Card */}
                    <Card className="border-border/60">
                      <CardContent className="p-5 space-y-4">
                        <div className="flex items-center justify-between gap-2">
                          <div className="flex items-center gap-2 min-w-0">
                            <div className="h-8 w-8 rounded-lg bg-primary/10 flex items-center justify-center shrink-0">
                              <Link2 className="h-4 w-4 text-primary" />
                            </div>
                            <h4 className="text-sm font-semibold truncate">{t("merchant.generateWebsite.contentRefLabel")}</h4>
                          </div>
                          {contentRefUrls.length < 3 && (
                            <Button
                              type="button"
                              variant="ghost"
                              size="sm"
                              className="h-7 px-2 shrink-0"
                              onClick={() => setContentRefUrls((arr) => [...arr, ""])}
                            >
                              <Plus className="h-3.5 w-3.5 mr-1" />
                              {t("common.add", "添加")}
                            </Button>
                          )}
                        </div>
                        <div className="space-y-2">
                          {contentRefUrls.map((url, idx) => (
                            <div key={idx} className="space-y-1">
                              <div className="flex gap-2">
                                <Input
                                  type="url"
                                  placeholder="https://..."
                                  value={url}
                                  onChange={(e) => {
                                    const next = [...contentRefUrls];
                                    next[idx] = e.target.value;
                                    setContentRefUrls(next);
                                  }}
                                />
                                {contentRefUrls.length > 1 && (
                                  <Button
                                    type="button"
                                    variant="ghost"
                                    size="icon"
                                    className="shrink-0 text-muted-foreground hover:text-destructive"
                                    onClick={() => setContentRefUrls((arr) => arr.filter((_, i) => i !== idx))}
                                  >
                                    <X className="h-4 w-4" />
                                  </Button>
                                )}
                              </div>
                              {idx === 0 && selectedRestaurant && url.includes(`/restaurant/${selectedRestaurant.id}`) && (
                                <p className="text-[11px] text-muted-foreground flex items-center gap-1 pl-0.5">
                                  <Info className="h-3 w-3" />
                                  {t("merchant.websiteManagement.xxmarketPrefilledHint", "已填入小熊市集本店主页链接，可清空或替换")}
                                </p>
                              )}
                            </div>
                          ))}
                        </div>
                        <p className="text-xs text-muted-foreground border-t pt-3">
                          {t("merchant.generateWebsite.contentRefHint")}
                        </p>
                      </CardContent>
                    </Card>

                    {/* Intent & Audience Card */}
                    <Card className="border-border/60">
                      <CardContent className="p-5 space-y-4">
                        <div className="flex items-center gap-2">
                          <div className="h-8 w-8 rounded-lg bg-primary/10 flex items-center justify-center">
                            <Sparkles className="h-4 w-4 text-primary" />
                          </div>
                          <h4 className="text-sm font-semibold">{t("merchant.websiteManagement.intentSection", "网站意图与受众")}</h4>
                        </div>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                          <div className="space-y-1.5">
                            <Label htmlFor="site_goal" className="text-xs text-muted-foreground">
                              {t("merchant.websiteManagement.siteGoal", "网站目标")}
                            </Label>
                            <select
                              id="site_goal"
                              value={form.site_goal}
                              onChange={(e) => updateField("site_goal", e.target.value)}
                              className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
                            >
                              <option value="">{t("merchant.websiteManagement.siteGoalAuto", "自动判断")}</option>
                              <option value="reservation">{t("merchant.websiteManagement.siteGoalReservation", "预订/订位")}</option>
                              <option value="showcase">{t("merchant.websiteManagement.siteGoalShowcase", "作品展示")}</option>
                              <option value="contact">{t("merchant.websiteManagement.siteGoalContact", "联系咨询")}</option>
                              <option value="ecommerce">{t("merchant.websiteManagement.siteGoalEcommerce", "电商购买")}</option>
                            </select>
                          </div>
                          <div className="space-y-1.5">
                            <Label htmlFor="page_structure" className="text-xs text-muted-foreground">
                              {t("merchant.websiteManagement.pageStructure", "页面结构")}
                            </Label>
                            <select
                              id="page_structure"
                              value={form.page_structure}
                              onChange={(e) => updateField("page_structure", e.target.value)}
                              className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
                            >
                              <option value="single">{t("merchant.websiteManagement.pageSingle", "单页滚动")}</option>
                              <option value="multi">{t("merchant.websiteManagement.pageMulti", "多页面")}</option>
                            </select>
                          </div>
                          <div className="space-y-1.5 sm:col-span-2">
                            <Label htmlFor="reservation_url" className="text-xs text-muted-foreground">
                              {t("merchant.websiteManagement.reservationUrl", "预订/外卖链接")}
                            </Label>
                            <Input
                              id="reservation_url"
                              type="url"
                              placeholder="https://..."
                              value={form.reservation_url}
                              onChange={(e) => updateField("reservation_url", e.target.value)}
                            />
                          </div>
                          <div className="space-y-1.5 sm:col-span-2">
                            <Label htmlFor="target_audience" className="text-xs text-muted-foreground">
                              {t("merchant.websiteManagement.targetAudience", "目标受众")}
                            </Label>
                            <Input
                              id="target_audience"
                              placeholder={t("merchant.websiteManagement.targetAudiencePlaceholder", "如：年轻潮流 / 高端商务 / 本地家庭 / 游客")}
                              value={form.target_audience}
                              onChange={(e) => updateField("target_audience", e.target.value)}
                            />
                          </div>
                        </div>
                      </CardContent>
                    </Card>


                    <Card className="border-border/60">
                      <CardContent className="p-5 space-y-4">
                        <div className="flex items-center gap-2">
                          <div className="h-8 w-8 rounded-lg bg-primary/10 flex items-center justify-center">
                            <Palette className="h-4 w-4 text-primary" />
                          </div>
                          <h4 className="text-sm font-semibold">{t("merchant.websiteManagement.styleSection")}</h4>
                        </div>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                          {fields.filter(f => ["price_range", "slogan", "style_preference", "color_scheme"].includes(f.key)).map(({ key, label }) => (
                            <div key={key} className="space-y-1.5">
                              <Label htmlFor={key} className="text-xs text-muted-foreground">{label}</Label>
                              <Input id={key} value={(form as any)[key]} onChange={(e) => updateField(key, e.target.value)} />
                            </div>
                          ))}
                        </div>
                        <div className="space-y-1.5 pt-2 border-t">
                          <Label htmlFor="style_reference_url" className="text-xs text-muted-foreground">
                            {t("merchant.generateWebsite.styleRefLabel")}
                          </Label>
                          <Input
                            id="style_reference_url"
                            type="url"
                            placeholder="https://..."
                            value={form.style_reference_url}
                            onChange={(e) => updateField("style_reference_url", e.target.value)}
                          />
                          <p className="text-[11px] text-muted-foreground">{t("merchant.generateWebsite.styleRefHint")}</p>
                        </div>
                      </CardContent>
                    </Card>
                  </div>
                </div>

                {/* Generate Action */}
                <div className="sticky bottom-0 bg-background/95 backdrop-blur-sm py-4 border-t -mx-2 px-2 sm:mx-0 sm:px-0">
                  <Button onClick={handleGenerate} disabled={generating} className="w-full" size="lg">
                    {generating ? (
                      <Loader2 className="h-4 w-4 animate-spin mr-2" />
                    ) : (
                      <Sparkles className="h-4 w-4 mr-2" />
                    )}
                    {generating ? t("merchant.generateWebsite.generating") : t("merchant.websiteManagement.generate")}
                  </Button>
                </div>
              </div>
            )}

            {/* Step 3: Result */}
            {step === 3 && (
              <div className="space-y-6">
                <h3 className="text-lg font-semibold">{t("merchant.websiteManagement.step3Title")}</h3>

                {generating ? (
                  <div className="flex flex-col items-center justify-center py-16 text-center">
                    <Loader2 className="h-10 w-10 animate-spin text-primary mb-4" />
                    <p className="text-muted-foreground">{t("merchant.generateWebsite.generating")}</p>
                  </div>
                ) : result ? (
                  <Card className="border-primary/20 bg-primary/5">
                    <CardContent className="p-6 space-y-4">
                      <div className="flex items-center gap-2 text-primary">
                        <Check className="h-5 w-5" />
                        <span className="font-semibold">{t("merchant.generateWebsite.success")}</span>
                      </div>
                      <p className="text-sm text-muted-foreground">{form.business_name}</p>
                      <div className="space-y-2">
                        {result.preview_url && (
                          <Button variant="outline" className="w-full justify-start" asChild>
                            <a href={result.preview_url} target="_blank" rel="noopener noreferrer">
                              <ExternalLink className="h-4 w-4 mr-2" />
                              {t("merchant.generateWebsite.preview")}
                            </a>
                          </Button>
                        )}
                        {result.edit_url && (
                          <Button variant="outline" className="w-full justify-start" asChild>
                            <a href={result.edit_url} target="_blank" rel="noopener noreferrer">
                              <ExternalLink className="h-4 w-4 mr-2" />
                              {t("merchant.generateWebsite.edit")}
                            </a>
                          </Button>
                        )}
                        {result.share_url && (
                          <div className="flex gap-2">
                            <Button variant="outline" className="flex-1 justify-start" asChild>
                              <a href={result.share_url} target="_blank" rel="noopener noreferrer">
                                <ExternalLink className="h-4 w-4 mr-2" />
                                {t("merchant.generateWebsite.share")}
                              </a>
                            </Button>
                            <Button variant="secondary" size="icon" onClick={() => handleCopy(result.share_url)}>
                              {copied ? <Check className="h-4 w-4" /> : <Copy className="h-4 w-4" />}
                            </Button>
                          </div>
                        )}
                      </div>
                      <Button onClick={handleBackToList} className="w-full mt-4">
                        <ArrowLeft className="h-4 w-4 mr-2" />
                        {t("merchant.websiteManagement.backToList")}
                      </Button>
                    </CardContent>
                  </Card>
                ) : null}
              </div>
            )}
          </CardContent>
        </Card>
      )}
    </div>
  );
};

export default AdminWebsiteManagement;
